class Component extends DCLogic {
  state = { agreed: true, resetSent: false, loginUsername: "", loginPassword: "" };

  renderVals() {
    const accent = this.props.accentColor ?? "#2563EB";
    const agreed = this.state.agreed;
    return {
      accent,
      loginTitle: this.props.loginTitle ?? "欢迎回来",
      tagline: this.props.tagline ?? "登录 Talko,继续你的对话",
      agreed,
      agreeBg: agreed ? accent : "#ffffff",
      agreeBorder: agreed ? accent : "#d4d9e0",
      registerBtnBg: agreed ? accent : "#c9d4e8",
      registerBtnShadow: agreed ? "0 6px 18px rgba(37, 99, 235, 0.25)" : "none",
      toggleAgree: () => this.setState(s => ({ agreed: !s.agreed })),
      resetSent: this.state.resetSent,
      sendReset: () => this.setState({ resetSent: true }),
      loginUsername: this.state.loginUsername,
      loginPassword: this.state.loginPassword,
      setLoginUsername: (e) => this.setState({ loginUsername: e.target.value }),
      setLoginPassword: (e) => this.setState({ loginPassword: e.target.value }),
      noop: () => {}
    };
  }
}

